fun Iterator<TvmInst>.checkNext(): TvmInst {
    check(hasNext()) {
        "Unexpected end of instruction list"
    }
    return next()
}

object TvmDecompilerImpl : TvmDecompiler {

    private fun parseHeader(
        iterator: Iterator<TvmInst>,
        otherMethods: Map<MethodId, TvmMethod>
    ): Header {
        val inst = iterator.checkNext()
        if (inst is TvmDictSpecialDictpushconstInst) {
            return parseDictHeader(inst, iterator, otherMethods)
        }

        error("Unknown header")
    }

    private fun parseDictHeader(
        instDictpush: TvmDictSpecialDictpushconstInst,
        iterator: Iterator<TvmInst>,
        otherMethods: Map<MethodId, TvmMethod>
    ): Header {
        val instDictigetJmpz = iterator.checkNext()
        check(instDictigetJmpz is TvmDictSpecialDictigetjmpzInst)
        val instThrowarg = iterator.checkNext()
        check(instThrowarg is TvmExceptionsThrowargInst)
        check(!iterator.hasNext())

        return Header(otherMethods.mapValues {
            MethodData(
                it.key.toString(),
                it.value.instList,
                listOf(
                    MethodArg(TvmStackEntryType.SLICE, "in_msg"),
                    MethodArg(TvmStackEntryType.CELL, "in_msg_full"),
                    MethodArg(TvmStackEntryType.INT, "in_msg_value"),
                    MethodArg(TvmStackEntryType.INT, "balance"),
                )
            )
        })
    }

    override fun decompile(boc: ByteArray): TvmDecompilerResult {
        val stdlibContent = TvmDecompilerImpl::class.java.getResourceAsStream("/stdlib.fc")!!.readAllBytes().toString(
            Charset.defaultCharset())
        val builtinContent = TvmDecompilerImpl::class.java.getResourceAsStream("/builtin.fc")!!.readAllBytes().toString(
            Charset.defaultCharset())

        val cp0InstructionRegistry = Cp0InstructionRegistry.create()
        val registry = ParserRegistry()

        val stdlibRegistry = StdlibRegistry(
            cp0InstructionRegistry,
            stdlibContent,
            builtinContent,
        )

        registerAlignmentParsers(registry)
        registerAppParsers(registry)
        registerRegistersParsers(registry)
        registerConstParsers(registry)
        registerStackParsers(registry)
//        registerArithmParsers(registry)
        registerContinuationParsers(registry)
        registerGlobalsParsers(registry)
        registerCellParsers(registry)
        registerEquivParsers(registry)
//        registerExceptionParsers(registry)
        registerTupleParsers(registry)
        registerVirtualInstructions(registry)

        stdlibRegistry.registerStdlibInstructions(registry)
        stdlibRegistry.registerSimpleAsmInstructions(registry)

        registry.dumpUnknownInstructions()

        val disassembly = disassembleBoc(boc)

        val mainMethodInstructions = disassembly.mainMethod.instList
        val mainMethodInstructionsIterator = mainMethodInstructions.iterator()

        val firstInstruction = mainMethodInstructionsIterator.checkNext()
        check(firstInstruction is TvmCodepageSetcpInst && firstInstruction.n == 0) {
            "Codepage is not set or is not 0"
        }

        val header = parseHeader(
            mainMethodInstructionsIterator,
            disassembly.methods
        )

        println("Parsed methods:")
        for (method in header.methods) {
            println("${method.key}")
                parseMethod(registry, method.value)
//            }
        }

        return object : TvmDecompilerResult{}
    }

    private fun parseMethod(registry: ParserRegistry, data: MethodData) {
        val inheritedStackTracker = InheritedStackTracker(data.args)
        val ctx = CodeBlockContext(inheritedStackTracker)

        ctx.append(AstElement.FunctionReturnType).append(AstElement.Raw(" "))

        val methodName = when (data.id) {
            "-1" -> "recv_external"
            "0" -> "recv_internal"
            else -> "method_${data.id}"
        }

        println("Parsing method $methodName")

        ctx
            .append(AstElement.Raw(methodName))
            .append(AstElement.Raw(" "))
            .append(AstElement.FunctionArgs(inheritedStackTracker))
            .append(AstElement.Raw(" method_id(${data.id}) impure "))
            .append(AstElement.Raw(" {\n"))

        try {
            parseCodeBlock(registry, ctx, data.instructions, "\t", true)
        } catch (e: Throwable) {
            println("Exception during parsing:")
            e.printStackTrace()
        }

        ctx.append(AstElement.Raw("}"))
        println(
            ctx.resolveCode(mutableMapOf(), emptyMap(), mutableMapOf(), mutableMapOf(), mutableMapOf(), registry)
                .replace("\t;\n", "\n").replace(Regex("\n\\s*\n"), "\n")
        )
    }

    private fun parseInstruction(
        registry: ParserRegistry,
        inst: TvmInst,
        ctx: CodeBlockContext,
        ident: String,
        nextElements: MutableList<TvmInst>
    ) {
//        ctx.append(AstElement.Raw(";; ${inst.mnemonic} $inst\n${ident}"))
        if (!registry.parse(ctx, inst, ident, nextElements)) {
            ctx.append(AstElement.Raw(";; unparsed: ${inst.mnemonic} ${inst}\n"))
        }
    }

    fun parseCodeBlock(
        registry: ParserRegistry,
        ctx: CodeBlockContext,
        instList2: List<TvmInst>,
        ident: String,
        ret: Boolean
    ) {
        val instList = instList2.toMutableList()

        var i = 0
        while (i < instList.size) {
            val inst = instList[i++]
            val nextElements = instList.subList(i, instList.size).toMutableList()
            try {
                ctx.append(AstElement.Raw(ident))
                val nextElementsSizePrev = nextElements.size
                parseInstruction(registry, inst, ctx, ident, nextElements)
                if (nextElements.size != nextElementsSizePrev) {
                    i += (nextElementsSizePrev - nextElements.size)
                }
                ctx.append(AstElement.Raw("\n"))
            } catch (ex: Throwable) {
                println("Exception during instruction parsing: ${inst.mnemonic} $inst")
                ex.printStackTrace()
                ctx.append(AstElement.Raw(";; exception: ${inst.mnemonic} ${inst}")).append(AstElement.Raw("\n"))
                break
            }
        }
        if (ret) {
            ctx.append(AstElement.Raw(ident)).append(AstElement.FunctionReturnStatement(ctx.stack.toList())).append(AstElement.Raw("\n"))
        }
    }
}
